### Road records since 2012 - UVA


::: {.cell}

```{.r .cell-code}
since_uva <- cbbdata::cbd_torvik_game_stats(type = "conf", team = "North Carolina") |> dplyr::filter(location == "A" & year > 2012) |> 
  dplyr::group_by(opp) |> 
  dplyr::summarise(
    W = sum(result == "W"), 
    L = sum(result == "L"),
    win_pct = W / (W+L)
  ) |> 
  dplyr::arrange(win_pct)

since_uva
